import { useEffect, useRef } from 'react';

const GraphBlock = ({R}) => {
	
	const canvasRef = useRef(null);
	
	function drawGraph(ctx, width, height, R) {
	  const cx = width / 2;
	  const cy = height / 2;

	  let fakeR = false;
	  R = Number(R);

	  if (isNaN(R) || R === 0) {
		R = 1;
		fakeR = true;
	  }

	  const scale = (cx - 25) / R;

	  ctx.clearRect(0, 0, width, height);

	  // ===== Область =====
	  ctx.fillStyle = 'rgba(0, 0, 255, 0.5)';

	  // Треугольник
	  ctx.beginPath();
	  ctx.moveTo(cx, cy);
	  ctx.lineTo(cx - R * scale, cy);
	  ctx.lineTo(cx, cy + R * scale);
	  ctx.closePath();
	  ctx.fill();

	  // Квадрат
	  ctx.fillRect(cx, cy, R * scale, -R * scale / 2);

	  // Четверть круга
	  ctx.beginPath();
	  ctx.arc(cx, cy, R * scale / 2, 0, Math.PI / 2);
	  ctx.lineTo(cx, cy);
	  ctx.fill();

	  // ===== Оси =====
	  ctx.strokeStyle = 'black';
	  ctx.lineWidth = 1;

	  ctx.beginPath();
	  ctx.moveTo(0, cy);
	  ctx.lineTo(width, cy);
	  ctx.moveTo(cx, 0);
	  ctx.lineTo(cx, height);
	  ctx.stroke();

	  // ===== Деления =====
	  ctx.fillStyle = 'black';
	  ctx.font = '12px sans-serif';

	  for (let i = -2 * R; i <= 2 * R; i++) {
		if (i === 0) continue;

		const x = cx + (i * scale) / 2;
		const y = cy - (i * scale) / 2;

		// Засечки
		ctx.fillRect(x - 1, cy - 3, 2, 6);
		ctx.fillRect(cx - 3, y - 1, 6, 2);

		const label = fakeR ? `${i / 2}R` : i / 2;

		ctx.fillText(label, x - 10, cy + 15);
		ctx.fillText(label, cx + 8, y + 4);
	  }
	}
	
	useEffect( () => {
		const canvas = canvasRef.current;
		if (!canvas) return;
		
		const ctx = canvas.getContext('2d');
		
		drawGraph(ctx, canvas.width, canvas.height, R);
	}, []);
  
	return (
		<canvas
			ref={canvasRef}
			width={500}
			height={500}
			className="graph"
		/>
	);
};

export default GraphBlock;
